import React, { type FunctionComponent, type PropsWithChildren, type ReactNode } from "react";
import {Box, Flex, Heading} from "../";
import { useSeparator } from "../../../Factory";
import type { IContainerProps } from "@lmb/kitsconcerto-types";



const Container: FunctionComponent<PropsWithChildren<IContainerProps>> = ({
                                                                              title,
                                                                              rightElement,
                                                                              children,
                                                                              childrenContainerProps = {},
                                                                              ...props
                                                                          }) => {
    const { cssProps, nativeProps } = useSeparator<any>(props);

    return (
        <Box
            bgColor="surface-0"
            borderRadius={8}
            w="full"
            overflow="hidden"
            mb={8}
            shadow="md"
            {...cssProps}
            {...nativeProps}
        >
            {(!!title || !!rightElement) && (
                <Flex
                    backgroundColor="surface-100"
                    borderTopLeftRadius={8}
                    borderTopRightRadius={8}
                    p={10}
                    flexDirection="row"
                    alignItems="center"
                    h={58}
                    justifyContent="space-between"
                >
                    {!!title && (
                        <Heading
                            as="h2"
                            fontSize="lg"
                            fontWeight="bold"
                            fontColor="black-alpha-90"
                            letterSpacing={0}
                            fontFamily="Poppins,Helvetica,sans-serif"
                            m={0}
                            p={0}
                        >
                            {title}
                        </Heading>
                    )}
                    {rightElement}
                </Flex>
            )}

            <Flex p={10} flexDirection="column" {...childrenContainerProps}>
                {children}
            </Flex>
        </Box>
    );
};

export default Container;
